<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  html, body { height: 100%; overflow: hidden; }
  body {
    font-family: "Ubuntu", "Segoe UI", "DejaVu Sans", sans-serif;
    font-size: 14px;
    color: #eee;
    user-select: none;
  }

  /* ---------- Desktop ---------- */
  #desktop {
    position: fixed;
    inset: 0;
    background:
      radial-gradient(1200px 700px at 70% 30%, rgba(233,84,32,.35), transparent 60%),
      radial-gradient(900px 600px at 20% 80%, rgba(119,33,111,.5), transparent 60%),
      linear-gradient(135deg, #2c001e 0%, #4a1039 45%, #77216f 75%, #e95420 130%);
    overflow: hidden;
  }
  #desktop::after {
    content: "";
    position: absolute; inset: 0;
    background-image: radial-gradient(rgba(255,255,255,.04) 1px, transparent 1px);
    background-size: 26px 26px;
    pointer-events: none;
  }

  /* ---------- Top bar ---------- */
  #topbar {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 30px;
    background: rgba(20, 18, 24, .92);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    font-size: 12.5px;
    z-index: 5000;
    border-bottom: 1px solid rgba(255,255,255,.06);
  }
  #topbar .tb-left { font-weight: 700; letter-spacing: .3px; }
  #topbar .tb-right { display: flex; gap: 10px; align-items: center; opacity: .9; }
  #clock { font-variant-numeric: tabular-nums; }

  /* ---------- Dock / taskbar ---------- */
  #taskbar {
    position: absolute;
    left: 0;
    top: 30px;
    bottom: 0;
    width: 68px;
    background: rgba(20, 18, 24, .82);
    backdrop-filter: blur(6px);
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 10px 0;
    gap: 10px;
    z-index: 4000;
    border-right: 1px solid rgba(255,255,255,.06);
  }
  .launcher {
    width: 52px;
    height: 52px;
    border: none;
    border-radius: 12px;
    background: rgba(255,255,255,.07);
    color: #eee;
    cursor: pointer;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 2px;
    font-size: 9px;
    transition: background .15s, transform .1s;
  }
  .launcher:hover { background: rgba(255,255,255,.16); }
  .launcher:active { transform: scale(.94); }
  .launcher .icon {
    width: 30px; height: 24px;
    display: flex; align-items: center; justify-content: center;
    font-size: 20px; line-height: 1;
  }
  .launcher.running::after {
    content: "";
    position: absolute;
    left: 3px;
    width: 4px; height: 4px;
    border-radius: 50%;
    background: #e95420;
  }
  .launcher { position: relative; }

  /* ---------- Windows ---------- */
  .app-window {
    position: absolute;
    width: 560px;
    height: 400px;
    min-width: 360px;
    min-height: 240px;
    background: #2b2b33;
    border-radius: 10px;
    box-shadow: 0 18px 50px rgba(0,0,0,.55), 0 0 0 1px rgba(255,255,255,.08);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
  }
  .app-window.hidden { display: none; }

  .titlebar {
    height: 38px;
    flex: 0 0 38px;
    background: linear-gradient(#3a3a44, #313139);
    display: flex;
    align-items: center;
    padding: 0 10px;
    cursor: grab;
    border-bottom: 1px solid rgba(0,0,0,.35);
  }
  .titlebar:active { cursor: grabbing; }
  .titlebar .title {
    flex: 1;
    text-align: center;
    font-weight: 700;
    font-size: 13px;
    color: #ddd;
    pointer-events: none;
  }
  .win-close {
    width: 24px; height: 24px;
    border: none;
    border-radius: 50%;
    background: #e95420;
    color: #fff;
    font-size: 13px;
    line-height: 1;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: filter .12s;
  }
  .win-close:hover { filter: brightness(1.2); }
  .win-body {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-height: 0;
    background: #24242b;
  }

  /* ---------- Files app ---------- */
  #files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 10px;
    background: #2e2e37;
    border-bottom: 1px solid rgba(0,0,0,.35);
    flex: 0 0 auto;
  }
  #files-up {
    border: none;
    background: rgba(255,255,255,.09);
    color: #eee;
    border-radius: 6px;
    padding: 5px 12px;
    cursor: pointer;
    font-size: 14px;
  }
  #files-up:hover:not(:disabled) { background: rgba(255,255,255,.18); }
  #files-up:disabled { opacity: .35; cursor: default; }
  #files-path {
    flex: 1;
    background: #1d1d23;
    border: 1px solid rgba(255,255,255,.09);
    border-radius: 6px;
    padding: 5px 10px;
    font-family: "Ubuntu Mono", Consolas, monospace;
    font-size: 13px;
    color: #ffb59a;
    white-space: nowrap;
    overflow-x: auto;
  }
  #files-list {
    flex: 1;
    overflow-y: auto;
    padding: 10px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(96px, 1fr));
    gap: 6px;
    align-content: start;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
    padding: 10px 4px;
    border-radius: 8px;
    cursor: pointer;
    text-align: center;
    word-break: break-all;
    font-size: 12.5px;
  }
  .fs-item:hover { background: rgba(255,255,255,.08); }
  .fs-item .fs-icon { font-size: 30px; line-height: 1; pointer-events: none; }
  .fs-item .fs-name { pointer-events: none; }
  .fs-empty { grid-column: 1 / -1; opacity: .55; padding: 20px; text-align: center; }

  /* ---------- Notepad app ---------- */
  #tabs {
    display: flex;
    align-items: center;
    gap: 4px;
    padding: 6px 8px 0 8px;
    background: #2e2e37;
    overflow-x: auto;
    flex: 0 0 auto;
  }
  .tab {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 6px 10px;
    background: rgba(255,255,255,.06);
    border-radius: 7px 7px 0 0;
    cursor: pointer;
    font-size: 12.5px;
    white-space: nowrap;
    color: #bbb;
    border: 1px solid transparent;
    border-bottom: none;
  }
  .tab:hover { background: rgba(255,255,255,.12); }
  .tab.active {
    background: #1d1d23;
    color: #fff;
    border-color: rgba(255,255,255,.1);
  }
  .tab .tab-x {
    opacity: .55;
    font-size: 11px;
    padding: 0 2px;
    border-radius: 3px;
  }
  .tab .tab-x:hover { opacity: 1; background: rgba(255,255,255,.15); }
  #new-tab {
    border: none;
    background: rgba(255,255,255,.09);
    color: #eee;
    border-radius: 6px;
    width: 26px; height: 26px;
    cursor: pointer;
    font-size: 15px;
    flex: 0 0 auto;
    margin-bottom: 4px;
  }
  #new-tab:hover { background: rgba(255,255,255,.2); }
  #editor {
    flex: 1;
    width: 100%;
    resize: none;
    border: none;
    outline: none;
    background: #1d1d23;
    color: #eaeaea;
    padding: 12px 14px;
    font-family: "Ubuntu Mono", Consolas, monospace;
    font-size: 14px;
    line-height: 1.5;
    min-height: 0;
    user-select: text;
  }

  ::-webkit-scrollbar { width: 9px; height: 9px; }
  ::-webkit-scrollbar-thumb { background: rgba(255,255,255,.18); border-radius: 5px; }
  ::-webkit-scrollbar-track { background: transparent; }
</style>
</head>
