      <span style="width:24px"></span>
      <span class="title">Notepad</span>
      <button class="win-close" title="Close">&#10005;</button>
    </div>
    <div class="win-body">
      <div id="tabs"></div>
      <textarea id="editor" spellcheck="false" placeholder="Start typing…"></textarea>
    </div>
  </div>
</div>

<script>
(function () {
  "use strict";

  /* ================= Clock ================= */
  var clockEl = document.getElementById("clock");
  function tick() {
    var d = new Date();
    var days = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
    var months = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
    function p(n) { return (n < 10 ? "0" : "") + n; }
    clockEl.textContent = days[d.getDay()] + " " + months[d.getMonth()] + " " +
      d.getDate() + "  " + p(d.getHours()) + ":" + p(d.getMinutes());
  }
  tick();
  setInterval(tick, 10000);

  /* ================= Window manager ================= */
  var zCounter = 200;
  var desktop = document.getElementById("desktop");

  function bringToFront(win) {
    win.style.zIndex = ++zCounter;
  }

  function setupWindow(winId, launcherId) {
    var win = document.getElementById(winId);
    var launcher = document.getElementById(launcherId);
    var titlebar = win.querySelector(".titlebar");
    var closeBtn = win.querySelector(".win-close");

    launcher.addEventListener("click", function () {
      win.classList.remove("hidden");
      launcher.classList.add("running");
      bringToFront(win);
    });
    closeBtn.addEventListener("click", function (e) {
      e.stopPropagation();
      win.classList.add("hidden");
      launcher.classList.remove("running");
    });
    win.addEventListener("mousedown", function () { bringToFront(win); });

    // Dragging
    var drag = null;
    titlebar.addEventListener("mousedown", function (e) {
      if (e.target === closeBtn) return;
      drag = { x: e.clientX - win.offsetLeft, y: e.clientY - win.offsetTop };
      bringToFront(win);
      e.preventDefault();
    });
    document.addEventListener("mousemove", function (e) {
      if (!drag) return;
      var nx = e.clientX - drag.x;
      var ny = e.clientY - drag.y;
      var maxX = desktop.clientWidth - 120;
      var maxY = desktop.clientHeight - 60;
      win.style.left = Math.min(Math.max(nx, -win.offsetWidth + 120), maxX) + "px";
      win.style.top = Math.min(Math.max(ny, 30), maxY) + "px";
    });
    document.addEventListener("mouseup", function () { drag = null; });
    return win;
  }

  setupWindow("files-window", "open-files");
  setupWindow("notepad-window", "open-notepad");

  /* ================= Files app ================= */
  // Folders are objects; files are strings (fake sizes).
  var FS = {
    bin: { bash: "1.2M", cat: "43K", cp: "153K", ls: "142K", mkdir: "88K", mv: "147K", rm: "72K", sh: "1.2M" },
    boot: { "vmlinuz-6.8.0-45-generic": "13M", "initrd.img-6.8.0-45-generic": "68M", grub: { "grub.cfg": "9.1K" } },
    dev: { null: "0", random: "0", sda: "0", tty: "0", zero: "0" },
    etc: {
      "fstab": "665B", "hostname": "8B", "hosts": "221B", "os-release": "386B",
      "passwd": "2.1K", "resolv.conf": "92B",
      apt: { "sources.list": "2.8K" },
      ssh: { "sshd_config": "3.2K" }
    },
    home: {
      user: {
        Documents: {
          "notes.txt": "1.4K",
          "resume.odt": "38K",
          "thesis-draft.md": "82K",
          projects: { "todo.md": "512B", "ideas.txt": "2.2K" }
        },
        Downloads: { "ubuntu-24.04-desktop-amd64.iso": "5.7G", "wallpaper.jpg": "3.1M" },
        Pictures: { "screenshot-2026-07-17.png": "812K", "vacation.jpg": "4.4M", Camera: {} },
        Music: { "mix.mp3": "8.3M" },
        Videos: {},
        ".bashrc": "3.7K",
        ".profile": "807B"
      }
    },
    lib: { "libc.so.6": "2.2M", modules: {} },
    opt: {},
    proc: { "cpuinfo": "0", "meminfo": "0", "uptime": "0" },
    root: { ".bashrc": "3.1K" },
    sbin: { "fdisk": "121K", "fsck": "55K", "init": "1.6M", "reboot": "27K" },
    srv: {},
    tmp: { "snap-private-tmp": {} },
    usr: {
      bin: { "python3": "6.9M", "gcc": "1.1M", "vim": "3.9M", "curl": "260K", "git": "3.8M" },
      lib: { firefox: {} },
      local: { bin: {}, share: {} },
      share: { doc: {}, icons: {}, fonts: {} }
    },
    var: {
      log: { "syslog": "1.8M", "auth.log": "204K", "kern.log": "633K" },
      cache: { apt: {} },
      spool: {},
      www: { html: { "index.html": "10K" } }
    }
  };

  var filesPathEl = document.getElementById("files-path");
  var filesListEl = document.getElementById("files-list");
  var filesUpBtn = document.getElementById("files-up");
  var cwd = []; // array of path segments; [] = root

  function getNode(segments) {
    var node = FS;
    for (var i = 0; i < segments.length; i++) {
      node = node[segments[i]];
      if (node == null || typeof node !== "object") return null;
    }
    return node;
  }

  function renderFiles() {
    var node = getNode(cwd);
    if (node === null) { cwd = []; node = FS; }
    filesPathEl.textContent = "/" + cwd.join("/");
    filesUpBtn.disabled = cwd.length === 0;
    filesListEl.innerHTML = "";

    var names = Object.keys(node).sort(function (a, b) {
      var aDir = typeof node[a] === "object";
      var bDir = typeof node[b] === "object";
      if (aDir !== bDir) return aDir ? -1 : 1;
      return a.localeCompare(b);
    });

    if (names.length === 0) {
      var empty = document.createElement("div");
      empty.className = "fs-empty";
      empty.textContent = "This folder is empty";
      filesListEl.appendChild(empty);
      return;
    }

    names.forEach(function (name) {
      var isDir = typeof node[name] === "object";
      var item = document.createElement("div");
      item.className = "fs-item";
      item.title = isDir ? "Folder — double-click to open" : "File (" + node[name] + ")";

      var icon = document.createElement("span");
      icon.className = "fs-icon";
      icon.textContent = isDir ? "\uD83D\uDCC1" : "\uD83D\uDCC4";

      var label = document.createElement("span");
      label.className = "fs-name";
      label.textContent = name;

      item.appendChild(icon);
      item.appendChild(label);

      if (isDir) {
        item.addEventListener("dblclick", function () {
          cwd.push(name);
          renderFiles();
        });
      }
      filesListEl.appendChild(item);
    });
  }

  filesUpBtn.addEventListener("click", function () {
    if (cwd.length > 0) {
      cwd.pop();
      renderFiles();
    }
  });

  renderFiles();

  /* ================= Notepad app ================= */
  var STORAGE_KEY = "ubuntu-notepad-v1";
  var tabsEl = document.getElementById("tabs");
  var editorEl = document.getElementById("editor");
  var state; // { tabs: [{id, name, content}], activeId, nextNum }

  function loadState() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        var parsed = JSON.parse(raw);
        if (parsed && Array.isArray(parsed.tabs) && parsed.tabs.length > 0) {
          return parsed;
        }
      }
    } catch (e) { /* corrupted storage — start fresh */ }
    return {
      tabs: [{ id: "t1", name: "Untitled 1", content: "" }],
      activeId: "t1",
      nextNum: 2
    };
  }

  function saveState() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    } catch (e) { /* storage unavailable — keep working in memory */ }
  }

  function activeTab() {
    for (var i = 0; i < state.tabs.length; i++) {
      if (state.tabs[i].id === state.activeId) return state.tabs[i];
    }
    state.activeId = state.tabs[0].id;
    return state.tabs[0];
  }

  function renderTabs() {
    // Remove old .tab elements, keep #new-tab
    Array.prototype.slice.call(tabsEl.querySelectorAll(".tab")).forEach(function (t) {
      t.remove();
    });
    var newTabBtn = document.getElementById("new-tab");

    state.tabs.forEach(function (tab) {
      var el = document.createElement("div");
      el.className = "tab" + (tab.id === state.activeId ? " active" : "");
      el.dataset.id = tab.id;

      var label = document.createElement("span");
      label.textContent = tab.name;
      el.appendChild(label);

      if (state.tabs.length > 1) {
        var x = document.createElement("span");
        x.className = "tab-x";
        x.textContent = "\u2715";
        x.title = "Close tab";
        x.addEventListener("click", function (e) {
          e.stopPropagation();
          closeTab(tab.id);
        });
        el.appendChild(x);
      }

      el.addEventListener("click", function () {
        state.activeId = tab.id;
        saveState();
        renderTabs();
        renderEditor();
      });

      tabsEl.insertBefore(el, newTabBtn);
    });
    renderEditor();
  }

  function renderEditor() {
    editorEl.value = activeTab().content;
  }

  function closeTab(id) {
    var idx = state.tabs.findIndex(function (t) { return t.id === id; });
    if (idx === -1 || state.tabs.length <= 1) return;
    state.tabs.splice(idx, 1);
    if (state.activeId === id) {
      state.activeId = state.tabs[Math.max(0, idx - 1)].id;
    }
    saveState();
    renderTabs();
  }

  editorEl.addEventListener("input", function () {
    activeTab().content = editorEl.value;
    saveState();
  });

  // Build #new-tab (must live inside #tabs)
  var newTabBtn = document.createElement("button");
  newTabBtn.id = "new-tab";
  newTabBtn.title = "New tab";
  newTabBtn.textContent = "+";
  tabsEl.appendChild(newTabBtn);
  newTabBtn.addEventListener("click", function () {
    var id = "t" + Date.now().toString(36) + Math.floor(Math.random() * 1e4).toString(36);
    var tab = { id: id, name: "Untitled " + state.nextNum, content: "" };
    state.nextNum++;
    state.tabs.push(tab);
    state.activeId = id;
    saveState();
    renderTabs();
    editorEl.focus();
  });

  state = loadState();
  renderTabs();
})();
</script>
</body>
</html>
